  ('fire-eq-eng-moex-00670', 'fire-eq-eng', 'fire-eq-eng-moex-106-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準，設於儲槽之固定式泡沫滅火設備，那一型泡沫放出口定義如下：供 固定頂儲槽槽底注入泡沫法之放出口，該泡沫放出口由泡沫輸送管（具有可以阻止儲槽內之公共危險物 品由該配管逆流之構造或機械），將發泡器或泡沫發生機所發生之泡沫予以輸送注入儲槽內，並由泡沫 放出口放出泡沫？', '["Ⅰ型", "Ⅱ型", "Ⅲ型", "Ⅳ型"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "3f2a359fefc1", "answer_pdf_sha1": "3e5a201a58c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
